    ('yotian tactician', 'Yotian Tactician', 'a265aaeb5e89871e6877e48b66ded6d3', 'battle_rule_v1:5037a89710fa8f2fe3658b333c2db3aa', '{"ability_kind":"static","battle_model_scope":"xmage_static_controlled_power_toughness_boost_v1","effect":"creature","permanent_type":"creature","static_applies_to":"creatures_you_control","static_effect":"controlled_power_toughness_boost","static_exclude_source":true,"static_power_bonus":1,"static_required_subtypes":["soldier"],"static_toughness_bonus":1,"target":"controlled_creatures","target_constraints":{"card_types":["creature"],"controller":"self","subtypes":["soldier"]},"target_controller":"self","xmage_ability_class":"SimpleStaticAbility","xmage_effect_class":"BoostControlledEffect"}'::jsonb, '{"category":"unknown","effect":"creature","target":"controlled_creatures"}'::jsonb, 'curated', 0.96, 'verified', 'auto', 'XMage authoritative exact-scope split: local class YotianTactician translated into ManaLoom runtime scope xmage_static_controlled_power_toughness_boost_v1. This row is package-ready only because the source signature is a narrow permanent static controlled-creature power/toughness boost with focused runtime coverage.', 'deprecate_nonmatching_rows')
),
  counts AS (
    SELECT
      p.card_name,
      p.normalized_name,
      p.oracle_hash,
      count(c.id) AS target_card_rows,
      min(c.id::text)::uuid AS canonical_card_id
    FROM proposed p
    LEFT JOIN public.cards c
      ON (
           lower(c.name) = p.normalized_name
           OR split_part(lower(c.name), ' // ', 1) = p.normalized_name
         )
     AND md5(coalesce(c.oracle_text, '')) = p.oracle_hash
    GROUP BY p.card_name, p.normalized_name, p.oracle_hash
  )
  SELECT jsonb_agg(counts ORDER BY card_name)
    INTO v_missing
  FROM counts
  WHERE target_card_rows < 1;

  IF v_missing IS NOT NULL THEN
    RAISE EXCEPTION 'XMage batch package abort: expected at least one Oracle-hash-matched card row for every proposed card: %', v_missing;
  END IF;
END $$;

